209	
210	        let zip_path = source_dir.path().join("test.hdpack");
211	        pack.export(source_dir.path(), &zip_path)?;
212	
213	        // Import it back
214	        // Note: import() uses get_profiles_dir() which points to XDG_CONFIG_HOME
215	        // For testing, we might want to mock get_profiles_dir() or just check the ZIP content directly first.
216	        // But let's try to run it and see if it works with the environment variables.
217	        
218	        let imported_pack = Pack::import(&zip_path)?;
